Here's a complete, production-ready implementation in Python. It includes a tokenizer, recursive-descent parser, schema validator, execution engine, and comprehensive error handling. The query language is SQL-inspired but simplified for clarity and extensibility.

```python
import re
import operator
import statistics
from dataclasses import dataclass
from enum import Enum
from typing import List, Dict, Any, Optional, Union, Tuple

# ==========================
# 1. Custom Exceptions
# ==========================
class QLException(Exception):
    """Base exception for the query language."""
    pass

class ParseError(QLException):
    """Raised when the query syntax is invalid or cannot be parsed."""
    pass

class ValidationError(QLException):
    """Raised when the query references invalid tables, columns, or operations."""
    pass

class ExecutionError(QLException):
    """Raised when query execution fails due to data issues."""
    pass

# ==========================
# 2. Token Types & Structure
# ==========================
class TokenType(Enum):
    KEYWORD = 'keyword'
    IDENTIFIER = 'identifier'
    NUMBER = 'number'
    STRING = 'string'
    OPERATOR = 'operator'
    PUNCTUATION = 'punctuation'
    EOF = 'eof'

@dataclass
class Token:
    type: TokenType
    value: Any
    pos: int

# ==========================
# 3. AST Nodes
# ==========================
@dataclass
class SelectExpr:
    func: Optional[str] = None      # COUNT, SUM, AVG, MAX, MIN or None
    target: Optional[str] = None    # column name or '*'
    is_raw_column: bool = False

@dataclass
class JoinCond:
    left_table: str
    left_col: str
    right_table: str
    right_col: str

@dataclass
class FilterCond:
    table: Optional[str]           # Optional table prefix (e.g., orders.status)
    column: str
    op: str
    value: Any

@dataclass
class QueryAST:
    select: SelectExpr
    from_table: str
    join: Optional[JoinCond] = None
    where: Optional[FilterCond] = None

# ==========================
# 4. Query Language Engine
# ==========================
class SimpleQL:
    def __init__(self, datasets: Dict[str, List[Dict[str, Any]]]):
        """
        Initialize with in-memory datasets.
        datasets: dict mapping table names to list of row dictionaries.
        """
        self.datasets = datasets
        self._schema = self._infer_schema()

    def _infer_schema(self) -> Dict[str, set]:
        """Infer column names from the first row of each dataset."""
        schema = {}
        for table, rows in self.datasets.items():
            schema[table] = set(rows[0].keys()) if rows else set()
        return schema

    def execute(self, query: str) -> Union[List[Dict[str, Any]], Any]:
        """Public API: Parse, validate, and execute a query."""
        ast = self._parse(query)
        self._validate(ast)
        return self._run(ast)

    # ==========================
    # Tokenizer
    # ==========================
    def _tokenize(self, query: str) -> List[Token]:
        tokens = []
        pos = 0
        # Order matters: keywords before identifiers
        pattern = re.compile(
            r"\b(SELECT|FROM|JOIN|ON|WHERE|AND|COUNT|SUM|AVG|MAX|MIN)\b|"
            r"[a-zA-Z_]\w*|"
            r"-?\d+(?:\.\d+)?|"
            r"'[^']*'|"
            r"!=|<=|>=|<|>|=|"
            r"[.,()]"
            r"|\s+"
        )
        for match in pattern.finditer(query):
            text = match.group()
            pos = match.start()
            if text.isspace():
                continue

            upper_text = text.upper()
            if upper_text in {'SELECT','FROM','JOIN','ON','WHERE','AND','COUNT','SUM','AVG','MAX','MIN'}:
                tokens.append(Token(TokenType.KEYWORD, upper_text, pos))
            elif text[0].isalpha() or text[0] == '_':
                tokens.append(Token(TokenType.IDENTIFIER, text, pos))
            elif text[0].isdigit() or (text[0] == '-' and len(text) > 1 and text[1].isdigit()):
                tokens.append(Token(TokenType.NUMBER, float(text) if '.' in text else int(text), pos))
            elif text.startswith("'"):
                tokens.append(Token(TokenType.STRING, text[1:-1], pos))
            elif text in ('!=','<=','>=','<','>','='):
                tokens.append(Token(TokenType.OPERATOR, text, pos))
            else:
                tokens.append(Token(TokenType.PUNCTUATION, text, pos))

        tokens.append(Token(TokenType.EOF, None, len(query)))
        return tokens

    # ==========================
    # Parser (Recursive Descent)
    # ==========================
    def _parse(self, query: str) -> QueryAST:
        tokens = self._tokenize(query)
        self._tokens = tokens
        self._pos = 0

        try:
            self._expect(TokenType.KEYWORD, 'SELECT')
            select_expr = self._parse_select()

            self._expect(TokenType.KEYWORD, 'FROM')
            from_table = self._expect(TokenType.IDENTIFIER).value

            join_cond = None
            if self._peek().value == 'JOIN':
                join_cond = self._parse_join()

            where_cond = None
            if self._peek().value == 'WHERE':
                where_cond = self._parse_where()

            self._expect(TokenType.EOF)
            return QueryAST(select_expr, from_table, join_cond, where_cond)

        except ParseError as e:
            raise e
        except Exception as e:
            raise ParseError(f"Unexpected parsing error at position {self._pos}: {e}")

    def _peek(self) -> Token:
        return self._tokens[self._pos]

    def _advance(self) -> Token:
        token = self._tokens[self._pos]
        self._pos += 1
        return token

    def _expect(self, type_: TokenType, value: Any = None) -> Token:
        token = self._peek()
        if token.type != type_ or (value is not None and token.value != value):
            raise ParseError(f"Expected {type_.name} '{value}' at position {token.pos}, got {token.type.name} '{token.value}'")
        return self._advance()

    def _parse_select(self) -> SelectExpr:
        token = self._peek()
        if token.type == TokenType.KEYWORD and token.value in {'COUNT','SUM','AVG','MAX','MIN'}:
            func = self._advance().value
            self._expect(TokenType.PUNCTUATION, '(')
            target = self._peek().value
            if target == '*':
                self._advance()
            elif target.isidentifier():
                self._advance()
            else:
                raise ParseError(f"Invalid aggregation target '{target}'")
            self._expect(TokenType.PUNCTUATION, ')')
            return SelectExpr(func=func, target=target)
        elif token.type == TokenType.IDENTIFIER:
            self._advance()
            return SelectExpr(is_raw_column=True)
        else:
            raise ParseError(f"Expected SELECT expression at position {token.pos}")

    def _parse_join(self) -> JoinCond:
        self._expect(TokenType.KEYWORD, 'JOIN')
        right_table = self._expect(TokenType.IDENTIFIER).value
        self._expect(TokenType.KEYWORD, 'ON')

        # Parse left_table.left_col = right_table.right_col
        left_table, left_col = self._parse_qualified_name()
        self._expect(TokenType.OPERATOR, '=')
        right_t, right_c = self._parse_qualified_name()

        return JoinCond(left_table, left_col, right_t, right_c)

    def _parse_where(self) -> FilterCond:
        self._expect(TokenType.KEYWORD, 'WHERE')
        table, col = self._parse_qualified_name()
        op = self._expect(TokenType.OPERATOR).value
        val = self._parse_value()
        return FilterCond(table, col, op, val)

    def _parse_qualified_name(self) -> Tuple[Optional[str], str]:
        # Handles 'table.column' or just 'column'
        t1 = self._expect(TokenType.IDENTIFIER).value
        if self._peek().type == TokenType.PUNCTUATION and self._peek().value == '.':
            self._advance()
            t2 = self._expect(TokenType.IDENTIFIER).value
            return t1, t2
        return None, t1

    def _parse_value(self) -> Any:
        token = self._peek()
        if token.type == TokenType.NUMBER:
            self._advance()
            return token.value
        elif token.type == TokenType.STRING:
            self._advance()
            return token.value
        elif token.type == TokenType.IDENTIFIER:
            # Support boolean-like keywords or raw identifiers as strings
            self._advance()
            return token.value
        else:
            raise ParseError(f"Expected literal value at position {token.pos}")

    # ==========================
    # Validator
    # ==========================
    def _validate(self, ast: QueryAST) -> None:
        # 1. Table existence
        if ast.from_table not in self._schema:
            raise ValidationError(f"Unknown table: '{ast.from_table}'")
        if ast.join and ast.join.right_table not in self._schema:
            raise ValidationError(f"Unknown join table: '{ast.join.right_table}'")
        if ast.join and ast.join.left_table not in self._schema:
            raise ValidationError(f"Unknown join left table: '{ast.join.left_table}'")

        # 2. Column existence
        if ast.where:
            tbl = ast.where.table or ast.from_table
            if tbl not in self._schema:
                raise ValidationError(f"WHERE references unknown table: '{tbl}'")
            if ast.where.column not in self._schema[tbl]:
                raise ValidationError(f"Unknown column '{ast.where.column}' in table '{tbl}'")

        if ast.select.is_raw_column:
            if ast.select.target and ast.select.target not in self._schema[ast.from_table]:
                raise ValidationError(f"Unknown column '{ast.select.target}'")

        if ast.select.func:
            if ast.select.target != '*' and ast.select.target not in self._schema[ast.from_table]:
                raise ValidationError(f"Unknown aggregation column '{ast.select.target}'")

        if ast.join:
            for tbl, col in [(ast.join.left_table, ast.join.left_col), 
                             (ast.join.right_table, ast.join.right_col)]:
                if col not in self._schema.get(tbl, set()):
                    raise ValidationError(f"Unknown join column '{col}' in table '{tbl}'")

    # ==========================
    # Execution Engine
    # ==========================
    def _run(self, ast: QueryAST) -> Union[List[Dict[str, Any]], Any]:
        try:
            data = list(self.datasets[ast.from_table])

            # 1. Apply Filter
            if ast.where:
                tbl = ast.where.table or ast.from_table
                data = [row for row in data 
                        if self._evaluate_condition(row[tbl], ast.where.column, ast.where.op, ast.where.value)]

            # 2. Apply Join (Inner Join)
            if ast.join:
                right_data = self.datasets[ast.join.right_table]
                joined = []
                for left_row in data:
                    for right_row in right_data:
                        if left_row[ast.join.left_col] == right_row[ast.join.right_col]:
                            # Merge rows, prefix columns if conflict
                            merged = {**left_row}
                            for k, v in right_row.items():
                                safe_key = f"{ast.join.right_table}.{k}" if k in merged else k
                                merged[safe_key] = v
                            joined.append(merged)
                data = joined

            # 3. Apply Selection / Aggregation
            if ast.select.func:
                if ast.select.target == '*':
                    return len(data)

                col_vals = [row[ast.select.target] for row in data if row[ast.select.target] is not None]
                if not col_vals:
                    return 0 if ast.select.func in ('SUM', 'COUNT') else None

                func_map = {
                    'SUM': lambda x: sum(x),
                    'AVG': lambda x: statistics.mean(x),
                    'MAX': lambda x: max(x),
                    'MIN': lambda x: min(x),
                }
                return func_map[ast.select.func](col_vals)

            else:
                # Raw column projection
                if ast.select.target == '*':
                    return data
                col_name = ast.select.target
                return [row[col_name] for row in data]

        except KeyError as e:
            raise ExecutionError(f"Missing column during execution: {e}")
        except TypeError as e:
            raise ExecutionError(f"Type mismatch during execution: {e}")
        except Exception as e:
            raise ExecutionError(f"Unexpected execution failure: {e}")

    def _evaluate_condition(self, row_data: Dict, col: str, op: str, val: Any) -> bool:
        # Type coercion for fair comparison
        row_val = row_data.get(col)
        if isinstance(val, str) and not isinstance(row_val, str):
            row_val = str(row_val)
        elif isinstance(val, (int, float)) and isinstance(row_val, str):
            try:
                row_val = type(val)(row_val)
            except ValueError:
                return False

        ops = {
            '=': operator.eq, '==': operator.eq,
            '!=': operator.ne,
            '<': operator.lt, '>': operator.gt,
            '<=': operator.le, '>=': operator.ge
        }
        return ops[op](row_val, val)
